// Parser la sortie de iface-saturation.py
const stdout = $input.item.json.stdout || '';
const exitCode = $input.item.json.exitCode ?? 0;

// Extraire le code de sortie depuis la sortie (echo "EXIT:$?")
let realExit = exitCode;
const exitMatch = stdout.match(/EXIT:(\d+)/);
if (exitMatch) realExit = parseInt(exitMatch[1]);

// Compter les alertes déclenchées
const alertLines = stdout.split('\n').filter(l => l.includes('ALERTE ['));
const critCount = alertLines.filter(l => l.includes('[CRITICAL]')).length;
const highCount = alertLines.filter(l => l.includes('[HIGH]')).length;
const medCount  = alertLines.filter(l => l.includes('[MEDIUM]')).length;
const total = critCount + highCount + medCount;

// Extraire les interfaces alertées
const ifaces = alertLines.map(l => {
  const m = l.match(/ALERTE \[[A-Z]+\] (.+) (ingress|egress): ([\d.]+)%/);
  return m ? { iface: m[1], direction: m[2], pct: parseFloat(m[3]) } : null;
}).filter(Boolean);

// Vérifier si Prometheus est absent
const promAbsent = stdout.includes('Prometheus non joignable') || stdout.includes('arrêt gracieux');

console.log(`[iface-saturation] exit=${realExit} | alertes=${total} (crit=${critCount} high=${highCount} med=${medCount}) | prom_absent=${promAbsent}`);

return [{
  json: {
    stdout,
    exitCode: realExit,
    total,
    critCount,
    highCount,
    medCount,
    ifaces,
    promAbsent,
    hasAlerts: total > 0,
    timestamp: new Date().toISOString()
  }
}];

// Construire un résumé Teams si des alertes sont présentes
const {
  total, critCount, highCount, medCount, ifaces, timestamp
} = $input.item.json;

const alertColor = critCount > 0 ? 'Attention' : highCount > 0 ? 'Warning' : 'Default';
const emoji = critCount > 0 ? '🚨' : '⚠️';

// Tableau des interfaces en alerte
const ifaceFacts = ifaces.length > 0
  ? ifaces.slice(0, 5).map(i => ({
      title: `${i.iface} (${i.direction})`,
      value: `${i.pct.toFixed(1)}%`
    }))
  : [{ title: 'Interfaces', value: 'Aucune donnée' }];

const dateStr = new Date(timestamp).toLocaleString('fr-FR', {
  timeZone: 'Europe/Paris',
  dateStyle: 'short',
  timeStyle: 'short'
});

const payload = {
  type: 'message',
  attachments: [{
    contentType: 'application/vnd.microsoft.card.adaptive',
    content: {
      '$schema': 'http://adaptivecards.io/schemas/adaptive-card.json',
      type: 'AdaptiveCard',
      version: '1.4',
      body: [
        {
          type: 'TextBlock',
          text: `${emoji} Saturation Interface — ${dateStr}`,
          weight: 'Bolder',
          size: 'Large',
          color: alertColor,
          wrap: true
        },
        {
          type: 'FactSet',
          facts: [
            { title: 'Total alertes', value: String(total) },
            { title: 'Critical',      value: String(critCount) },
            { title: 'High',          value: String(highCount) },
            { title: 'Medium',        value: String(medCount) }
          ]
        },
        {
          type: 'TextBlock',
          text: 'Interfaces en alerte',
          weight: 'Bolder',
          size: 'Small',
          separator: true
        },
        {
          type: 'FactSet',
          facts: ifaceFacts
        }
      ],
      actions: [{
        type: 'Action.OpenUrl',
        title: 'Ouvrir NetWatch',
        url: 'http://localhost:5050'
      }]
    }
  }]
};

return [{ json: payload }];
